"use strict";
const Commons = require("../utils/commons");
const RequestUtils = require("../utils/requestUtils");
async function sendDisbursementRequest({ apiKey, amount, currency, phoneNumber, webhookUrl, }) {
    const requestData = {
        recipientPhoneNumber: phoneNumber,
        currency,
        amount,
        webhookUrl,
    };
    const disbursementRequestResponse = await RequestUtils.sendRequestTo(Commons.serverBaseUrl() + '/deposit?apikey=' + apiKey, requestData, null, 'post', true);
    if (disbursementRequestResponse.response.error && disbursementRequestResponse.response.error.msg) {
        return {
            success: false,
            message: disbursementRequestResponse.response.error.msg,
            deposit: { statusMessageCode: disbursementRequestResponse.status.code },
        };
    }
    if (disbursementRequestResponse.response.error) {
        return {
            success: false,
            message: 'error',
            deposit: { statusMessageCode: disbursementRequestResponse.status.code },
        };
    }
    if (!/^2../.test(disbursementRequestResponse.status.code)) {
        return Object.assign(Object.assign({ success: false, message: 'error' }, disbursementRequestResponse.response), { deposit: Object.assign(Object.assign({}, (disbursementRequestResponse.response.deposit || {})), { statusMessageCode: disbursementRequestResponse.status.code }) });
    }
    return disbursementRequestResponse.response;
}
module.exports = sendDisbursementRequest;
